// Obtém os dados da execução anterior (Switch)
const data = $input.all();

// Mensagem personalizada sobre o relatório
let mensagem = `<p>Prezados,</p>
<p>Segue o relatório com os equipamentos que atualmente estão vinculados a colaboradores desligados da empresa. Solicitamos a regularização desses ativos o mais breve possível, a fim de evitar problemas operacionais e garantir a devida alocação dos equipamentos.</p>
<p>Caso haja dúvidas ou a necessidade de mais informações, por favor, entre em contato com o setor responsável.</p>
<p>Agradecemos pela atenção e colaboração.</p>`;

// Inicia a tabela HTML
let htmlTable = `<table border="1" cellpadding="5" cellspacing="0">
<thead>
<tr>
<th>NOME</th>
<th>ID</th>
<th>MODELO</th>
<th>FABRICANTE</th>
<th>LOCAL</th>
</tr>
</thead>
<tbody>`;

// Loop através dos dados e adicionar cada linha à tabela
data.forEach(item => {
  htmlTable += `<tr>
  <td>${item.json.NOME}</td>
  <td>${item.json.ID}</td>
  <td>${item.json.MODELO}</td>
  <td>${item.json.FABRICANTE}</td>
  <td>${item.json.LOCAL}</td>
  </tr>`;
});

// Fecha a tabela
htmlTable += `</tbody></table>`;

// Assinatura após a tabela
let assinatura = `<p>Atenciosamente,</p>
<p>Tecnologia da informação.</p>`;

// Combina a mensagem, a tabela e a assinatura
const emailBody = mensagem + htmlTable + assinatura;

// Retorna o corpo do e-mail completo
return [{ emailBody }];

